import { Grid, Typography, Box } from "@mui/material";

const skills = [
  {
    id: 1,
    name: "HTML",
  },
  {
    id: 2,
    name: "CSS",
  },
];
export const Skills = () => {
  return (
    <Grid container>
      <Grid item xs={6}>
        <Box sx={{border:'5px solid black'}}>
          <Typography variant="h4">What can I do</Typography>
          {skills.map((skill) => (
            <Box component="div" key={skill.id} mt={2}>
              <Typography variant="h6" color="textPrimary">
              &#x2714; {skill.name}

              </Typography>
              <Typography variant="h6" color="textPrimary">
            Description 

              </Typography>
            </Box>
          ))}
        </Box>
      </Grid>
      <Grid item xs={6}></Grid>
    </Grid>
  );
};
